// ─── Types ────────────────────────────────────────────────────────────────────

export interface TNTRow {
  ref: string        // S58606
  dest: string       // Destinataire
  dept: string       // 75
  weight: number     // kg
  transportHT: number // €
  date: string
}

export interface OdooRow {
  ref: string        // S58606
  client: string
  commandeHT: number
  rawRef: string
}

export interface CrossedRow {
  ref: string
  client: string
  dept: string
  weight: number
  transportHT: number
  commandeHT: number
  pct: number         // % transport / commande
  matched: boolean
  odooOnly?: boolean
}

